{"code": "import json

# Load results from all processed queries
batch1 = locals()['var_functions.query_db:38']
batch2 = locals()['var_functions.query_db:48']
batch3 = locals()['var_functions.query_db:50']

# Function to filter and convert
def process_batch(batch):
    good_stocks = []
    for stock in batch:
        if stock['up_days'] != 'nan' and stock['down_days'] != 'nan':
            up = float(stock['up_days'])
            down = float(stock['down_days'])
            if up > down:
                good_stocks.append({
                    'symbol': stock['symbol'],
                    'up_days': up,
                    'down_days': down,
                    'net': up - down
                })
    return good_stocks

# Process all batches
all_good = {}
for stock in process_batch(batch1) + process_batch(batch2) + process_batch(batch3):
    if stock['symbol'] not in all_good or stock['net'] > all_good[stock['symbol']]['net']:
        all_good[stock['symbol']] = stock

# Get top 5
top_5 = sorted(all_good.values(), key=lambda x: x['net'], reverse=True)[:5]
print(f"Top 5 stocks found: {len(top_5)}")
for i, stock in enumerate(top_5, 1):
    print(f"{i}. {stock['symbol']}: +{stock['net']:.0f} net up days")
result = {'top_5_symbols': [s['symbol'] for s in top_5]}
print('__RESULT__:')
print(json.dumps(result))"}

